import java.sql.*;

// A block where exceptions may occur
try (Connection conn = DriverManager.getConnection(url, user, pw);
     Statement stmt = conn.createStatement()) {

    // Executing a SELECT statement
    // Variable declaration and initialization
    String sql = "SELECT id, name, price FROM products " +
                 "WHERE price > 1000 ORDER BY price";
    ResultSet rs = stmt.executeQuery(sql);

    // Processing results
    // Repeat while the condition is true
    while (rs.next()) {
        int id = rs.getInt("id");
        String name = rs.getString("name");
        double price = rs.getDouble("price");
        System.out.printf("ID=%d, Product Name=%s, Price=%.0f%n",
            id, name, price);
    }

    // When there are no results
    rs = stmt.executeQuery(
        "SELECT * FROM products WHERE id = -1");
    // Conditional branching
    if (!rs.next()) {
        System.out.println("No data");
    }
}

import java.sql.*;

// A block where exceptions may occur
try (Connection conn = DriverManager.getConnection(url, user, pw);
     Statement stmt = conn.createStatement()) {

    // INSERT
    // Variable declaration and initialization
    int inserted = stmt.executeUpdate(
        "INSERT INTO products (name, price) " +
        "VALUES ('Java Book', 3000)");
    System.out.println(inserted + " row(s) inserted"); // 1 row(s) inserted

    // UPDATE
    int updated = stmt.executeUpdate(
        "UPDATE products SET price = 3500 " +
        "WHERE name = 'Java Book'");
    System.out.println(updated + " row(s) updated");

    // DELETE
    int deleted = stmt.executeUpdate(
        "DELETE FROM products WHERE price < 500");
    System.out.println(deleted + " row(s) deleted");

    // execute() method
    boolean hasResultSet = stmt.execute(
        "SELECT * FROM products");
    // Conditional branching
    if (hasResultSet) {
        ResultSet rs = stmt.getResultSet();
        // Repeat while the condition is true
        while (rs.next()) {
            System.out.println(rs.getString("name"));
        }
    }
}

import java.sql.*;

// Creating a scrollable ResultSet
Statement stmt = conn.createStatement(
    ResultSet.TYPE_SCROLL_INSENSITIVE,
    ResultSet.CONCUR_READ_ONLY);

ResultSet rs = stmt.executeQuery(
    "SELECT * FROM products");

// Move to the first row
rs.first();
System.out.println(rs.getString("name"));

// Move to the last row
rs.last();
System.out.println(rs.getString("name"));

// Move to the previous row
rs.previous();

// Move to a specific row (1-based)
rs.absolute(3); // Row 3

// Relative move
rs.relative(-1); // Move 1 row back
rs.relative(2);  // Move 2 rows forward

