import java.sql.*;

try (Connection conn = DriverManager.getConnection(url, user, pw)) {
    // Disable auto-commit
    conn.setAutoCommit(false);

    try (Statement stmt = conn.createStatement()) {
        // Transfer: Withdraw from A
        stmt.executeUpdate(
            "UPDATE accounts SET balance = balance - 10000 " +
            "WHERE name = 'A'");

        // Transfer: Deposit to B
        stmt.executeUpdate(
            "UPDATE accounts SET balance = balance + 10000 " +
            "WHERE name = 'B'");

        // Commit if all successful
        conn.commit();
        System.out.println("Transfer complete");

    } catch (SQLException e) {
        // Rollback on error
        conn.rollback();
        System.err.println("Transfer failed, rollback executed");
        throw e;
    }
}

import java.sql.*;

try (Connection conn = DriverManager.getConnection(url, user, pw)) {
    conn.setAutoCommit(false);
    Statement stmt = conn.createStatement();

    // Operation 1
    stmt.executeUpdate(
        "INSERT INTO logs (msg) VALUES ('Operation1')");

    // Set a Savepoint
    Savepoint sp = conn.setSavepoint("after_op1");

    try {
        // Operation 2 (may fail)
        stmt.executeUpdate(
            "INSERT INTO logs (msg) VALUES ('Operation2')");
        // Error occurs!
        throw new SQLException("Error in operation 2");
    } catch (SQLException e) {
        // Rollback to Savepoint (Operation 1 is preserved)
        conn.rollback(sp);
        System.out.println("Only operation 2 rolled back");
    }

    // Commit only Operation 1
    conn.commit();
}

